# search hadiths for top overlaps
def get_hadith_text(entry):
    # hadith JSON might have hadithTxt or Matn fields
    if 'hadithTxt' in entry:
        return entry['hadithTxt']
    elif 'Matn' in entry:
        return entry['Matn']
    elif 'text' in entry:
        return entry['text']
    else:
        # fallback to string representation
        return " ".join([str(v) for v in entry.values() if isinstance(v,str)])

